     1→import { paymentMiddleware } from 'x402-express';
     2→import { createThirdwebClient } from 'thirdweb';
     3→import { facilitator as createFacilitator } from 'thirdweb/x402';
     4→import { createPlaceholder, getSkill } from '../storage.js';
     5→import { runPipeline } from '../pipeline/index.js';
     6→
     7→const BASE_URL = process.env.BASE_URL || 'http://localhost:3000';
     8→
     9→function buildPaymentMiddleware(payToAddress) {
    10→  const client = createThirdwebClient({ secretKey: process.env.THIRDWEB_SECRET_KEY });
    11→  const thirdwebFacilitator = createFacilitator({ client, serverWalletAddress: payToAddress });
    12→  return paymentMiddleware(
    13→    payToAddress,
    14→    {
    15→      'POST /skills/generate': {
    16→        price: '$0.10',
    17→        network: 'base',
    18→        config: { description: 'Generate an Agent Skill for a smart contract ($0.10 USDC)' },
    19→      },
    20→      'GET /skills/[id]': {
    21→        price: '$0.01',
    22→        network: 'base',
    23→        config: { description: 'Download a generated Agent Skill ($0.01 USDC)' },
    24→      },
    25→    },
    26→    thirdwebFacilitator,
    27→  );
    28→}
    29→
    30→export function registerSkillsRoutes(app) {
    31→  const payToAddress = process.env.THIRDWEB_SERVER_WALLET_ADDRESS;
    32→  if (payToAddress) {
    33→    app.use(buildPaymentMiddleware(payToAddress));
    34→  }
    35→
    36→  app.post('/skills/generate', async (req, res) => {
    37→    const { contractAddress, message } = req.body ?? {};
    38→
    39→    if (!contractAddress) {
    40→      return res.status(400).json({ error: 'contractAddress is required' });
    41→    }
    42→
    43→    const id = crypto.randomUUID();
    44→    const url = `${BASE_URL}/skills/${id}`;
    45→
    46→    await createPlaceholder(id, { contractAddress });
    47→
    48→    runPipeline(id, contractAddress, message).catch(err => {
    49→      console.error(`Pipeline failed for skill ${id}:`, err);
    50→    });
    51→
    52→    return res.json({ id, url });
    53→  });
    54→
    55→  app.get('/skills/:id', async (req, res) => {
    56→    const { id } = req.params;
    57→
    58→    const skill = await getSkill(id);
    59→    if (!skill) return res.status(404).json({ error: 'Skill not found' });
    60→    const status = skill.status === 'generating' ? 'processing' : skill.status;
    61→    return res.json({ status, content: skill.content });
    62→  });
    63→}
    64→

