     1→import { S3Client, PutObjectCommand, GetObjectCommand } from '@aws-sdk/client-s3';
     2→
     3→let client;
     4→
     5→function getClient() {
     6→  if (!client) {
     7→    client = new S3Client({
     8→      endpoint: process.env.S3_ENDPOINT,
     9→      region: process.env.S3_REGION ?? 'auto',
    10→      credentials: {
    11→        accessKeyId: process.env.S3_ACCESS_KEY,
    12→        secretAccessKey: process.env.S3_SECRET_KEY,
    13→      },
    14→      forcePathStyle: true,
    15→    });
    16→  }
    17→  return client;
    18→}
    19→
    20→const bucket = () => process.env.S3_BUCKET;
    21→const key = (id) => `skills/${id}.json`;
    22→
    23→async function putSkillObject(id, obj) {
    24→  await getClient().send(new PutObjectCommand({
    25→    Bucket: bucket(),
    26→    Key: key(id),
    27→    Body: JSON.stringify(obj),
    28→    ContentType: 'application/json',
    29→  }));
    30→}
    31→
    32→export async function getSkill(id) {
    33→  try {
    34→    const response = await getClient().send(new GetObjectCommand({
    35→      Bucket: bucket(),
    36→      Key: key(id),
    37→    }));
    38→    const text = await response.Body.transformToString();
    39→    return JSON.parse(text);
    40→  } catch (err) {
    41→    if (err.name === 'NoSuchKey' || err.$metadata?.httpStatusCode === 404) {
    42→      return null;
    43→    }
    44→    throw err;
    45→  }
    46→}
    47→
    48→export async function createPlaceholder(id, metadata) {
    49→  await putSkillObject(id, {
    50→    id,
    51→    status: 'generating',
    52→    stage: 'research',
    53→    contractAddress: metadata.contractAddress,
    54→    chainId: 8453,
    55→    content: '',
    56→  });
    57→}
    58→
    59→export async function updateStage(id, stage) {
    60→  const obj = await getSkill(id);
    61→  if (!obj) throw new Error(`Skill ${id} not found`);
    62→  await putSkillObject(id, { ...obj, stage });
    63→}
    64→
    65→export async function markFailed(id, error) {
    66→  const obj = await getSkill(id);
    67→  const base = obj ?? { id, chainId: 8453, contractAddress: '', content: '' };
    68→  await putSkillObject(id, { ...base, status: 'failed', content: error });
    69→}
    70→
    71→export async function markReady(id, skillContent) {
    72→  const obj = await getSkill(id);
    73→  if (!obj) throw new Error(`Skill ${id} not found`);
    74→  await putSkillObject(id, { ...obj, status: 'ready', content: skillContent });
    75→}
