     1→import { readFileSync } from 'fs';
     2→import { dirname, join } from 'path';
     3→import { fileURLToPath } from 'url';
     4→import { HumanMessage, SystemMessage } from '@langchain/core/messages';
     5→import { model } from './model.js';
     6→
     7→const __dirname = dirname(fileURLToPath(import.meta.url));
     8→const ABI_SYSTEM_PROMPT = readFileSync(join(__dirname, 'prompts/validate-abi-system.md'), 'utf8');
     9→const SAFETY_SYSTEM_PROMPT = readFileSync(join(__dirname, 'prompts/validate-safety-system.md'), 'utf8');
    10→
    11→/**
    12→ * Parse YAML frontmatter from a SKILL.md string.
    13→ * Returns the raw frontmatter text between --- delimiters.
    14→ */
    15→function parseFrontmatter(content) {
    16→  const match = content.match(/^---\n([\s\S]*?)\n---/);
    17→  return match ? match[1] : null;
    18→}
    19→
    20→/**
    21→ * Check 1: Frontmatter validation.
    22→ * Verifies required fields: name, description, metadata.contractAddress, metadata.chainId, metadata.generator
    23→ * @returns {{ valid: boolean, errors: string[] }}
    24→ */
    25→export function checkFrontmatter(skillContent) {
    26→  const errors = [];
    27→  const fm = parseFrontmatter(skillContent);
    28→
    29→  if (!fm) {
    30→    return { valid: false, errors: ['Missing YAML frontmatter (--- delimiters not found)'] };
    31→  }
    32→
    33→  // Check top-level fields
    34→  if (!/^name:/m.test(fm)) errors.push('Missing required frontmatter field: name');
    35→  if (!/^description:/m.test(fm)) errors.push('Missing required frontmatter field: description');
    36→
    37→  // Check metadata block
    38→  if (!/^metadata:/m.test(fm)) {
    39→    errors.push('Missing required frontmatter field: metadata');
    40→  } else {
    41→    if (!/contractAddress:/m.test(fm)) errors.push('Missing required frontmatter field: metadata.contractAddress');
    42→    if (!/chainId:/m.test(fm)) errors.push('Missing required frontmatter field: metadata.chainId');
    43→    if (!/generator:/m.test(fm)) errors.push('Missing required frontmatter field: metadata.generator');
    44→  }
    45→
    46→  return { valid: errors.length === 0, errors };
    47→}
    48→
    49→/**
    50→ * Check 2: ABI cross-check via LLM.
    51→ * Verifies code examples reference real function signatures from the ABI.
    52→ * @returns {Promise<{ valid: boolean, errors: string[] }>}
    53→ */
    54→export async function checkABICrossCheck(skillContent, abi) {
    55→  if (!abi || abi.length === 0) {
    56→    return { valid: true, errors: [] }; // Can't check without ABI
    57→  }
    58→
    59→  const response = await model.invoke([
    60→    new SystemMessage(ABI_SYSTEM_PROMPT),
    61→    new HumanMessage(`Review the following SKILL.md code examples against the contract ABI.
    62→
    63→ABI:
    64→${JSON.stringify(abi, null, 2)}
    65→
    66→SKILL.md:
    67→${skillContent}
    68→
    69→Check that:
    70→1. All function names in code examples exist in the ABI
    71→2. Parameter types match the ABI signatures
    72→3. Return types are used correctly
    73→
    74→Respond with JSON: { "valid": boolean, "errors": string[] }
    75→If valid, errors should be an empty array.`),
    76→  ]);
    77→
    78→  const text = response.content;
    79→  const jsonMatch = text.match(/\{[\s\S]*\}/);
    80→  if (!jsonMatch) return { valid: true, errors: [] }; // Fail open if LLM response is unparseable
    81→
    82→  try {
    83→    return JSON.parse(jsonMatch[0]);
    84→  } catch {
    85→    return { valid: true, errors: [] };
    86→  }
    87→}
    88→
    89→/**
    90→ * Check 3: Safety check via LLM.
    91→ * Verifies the skill includes warnings for payable functions and approval patterns.
    92→ * @returns {Promise<{ valid: boolean, errors: string[] }>}
    93→ */
    94→export async function checkSafety(skillContent, abi) {
    95→  const payableFunctions = abi
    96→    ? abi.filter((item) => item.type === 'function' && item.stateMutability === 'payable').map((f) => f.name)
    97→    : [];
    98→
    99→  const hasApprovalPattern = abi
   100→    ? abi.some((item) => item.type === 'function' && ['approve', 'setApprovalForAll'].includes(item.name))
   101→    : false;
   102→
   103→  if (payableFunctions.length === 0 && !hasApprovalPattern) {
   104→    return { valid: true, errors: [] }; // Nothing to check
   105→  }
   106→
   107→  const response = await model.invoke([
   108→    new SystemMessage(SAFETY_SYSTEM_PROMPT),
   109→    new HumanMessage(`Review the following SKILL.md for safety warnings.
   110→
   111→${payableFunctions.length > 0 ? `Payable functions that need ETH value warnings: ${payableFunctions.join(', ')}` : ''}
   112→${hasApprovalPattern ? 'Contract has approval functions (approve/setApprovalForAll) that require approval-before-transfer warnings.' : ''}
   113→
   114→SKILL.md:
   115→${skillContent}
   116→
   117→Check that the skill includes appropriate warnings for:
   118→${payableFunctions.length > 0 ? '- Payable functions (user must send ETH value)' : ''}
   119→${hasApprovalPattern ? '- Approval patterns (approve before transferFrom, risks of unlimited approvals)' : ''}
   120→
   121→Respond with JSON: { "valid": boolean, "errors": string[] }
   122→If valid, errors should be an empty array.`),
   123→  ]);
   124→
   125→  const text = response.content;
   126→  const jsonMatch = text.match(/\{[\s\S]*\}/);
   127→  if (!jsonMatch) return { valid: true, errors: [] };
   128→
   129→  try {
   130→    return JSON.parse(jsonMatch[0]);
   131→  } catch {
   132→    return { valid: true, errors: [] };
   133→  }
   134→}
   135→
   136→/**
   137→ * Run all three validation checks and aggregate results.
   138→ * @param {string} skillContent - SKILL.md content
   139→ * @param {object[]} [abi] - contract ABI (optional, for ABI cross-check and safety)
   140→ * @returns {Promise<{ valid: boolean, errors: string[] }>}
   141→ */
   142→export async function runValidate(skillContent, abi = []) {
   143→  const frontmatterResult = checkFrontmatter(skillContent);
   144→  const [abiResult, safetyResult] = await Promise.all([
   145→    checkABICrossCheck(skillContent, abi),
   146→    checkSafety(skillContent, abi),
   147→  ]);
   148→
   149→  const errors = [
   150→    ...frontmatterResult.errors,
   151→    ...abiResult.errors,
   152→    ...safetyResult.errors,
   153→  ];
   154→
   155→  return { valid: errors.length === 0, errors };
   156→}
   157→

