     1→import { tool } from '@langchain/core/tools';
     2→import { z } from 'zod';
     3→import { fetchABI, fetchSourceCode } from './explorer.js';
     4→import { detectERCPatterns } from './erc.js';
     5→
     6→export const researchTools = [
     7→  tool(
     8→    async ({ contractAddress }) => {
     9→      const abi = await fetchABI(contractAddress);
    10→      if (!abi) return 'ABI not available for this contract';
    11→      return JSON.stringify(abi);
    12→    },
    13→    {
    14→      name: 'fetchABI',
    15→      description: 'Fetch the ABI of a smart contract from Blockscout (Base Mainnet)',
    16→      schema: z.object({
    17→        contractAddress: z.string().describe('The contract address to fetch ABI for'),
    18→      }),
    19→    }
    20→  ),
    21→
    22→  tool(
    23→    async ({ contractAddress }) => {
    24→      const source = await fetchSourceCode(contractAddress);
    25→      if (!source) return 'Source code not available for this contract';
    26→      return typeof source === 'string' ? source : JSON.stringify(source);
    27→    },
    28→    {
    29→      name: 'fetchSourceCode',
    30→      description: 'Fetch the verified source code of a smart contract from Blockscout (Base Mainnet)',
    31→      schema: z.object({
    32→        contractAddress: z.string().describe('The contract address to fetch source code for'),
    33→      }),
    34→    }
    35→  ),
    36→
    37→  tool(
    38→    async ({ abi }) => {
    39→      const patterns = detectERCPatterns(abi);
    40→      return JSON.stringify(patterns);
    41→    },
    42→    {
    43→      name: 'detectERCPatterns',
    44→      description: 'Detect ERC standards (ERC-20, ERC-721, ERC-1155, ERC-4626) from a contract ABI',
    45→      schema: z.object({
    46→        abi: z.array(z.any()).describe('The contract ABI as a JSON array'),
    47→      }),
    48→    }
    49→  ),
    50→];
